import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        a = int(next(it))
        b = int(next(it))
        c = int(next(it))
        total = a + 2 * b + 3 * c
        if total % 2 == 0:
            out_lines.append("0")
        else:
            if a > 0:
                out_lines.append("1")
            elif b > 0 and c > 0:
                out_lines.append("1")
            else:
                out_lines.append("3")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

