import sys, math

def solve() -> None:
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    t = next(it, 0)
    out_lines = []
    for _ in range(t):
        n = next(it)
        cnt = [0] * 30
        for _ in range(n):
            x = next(it)
            b = 0
            while x:
                if x & 1:
                    cnt[b] += 1
                x >>= 1
                b += 1
        g = 0
        for c in cnt:
            if c:
                g = math.gcd(g, c)
        if g == 0:
            out_lines.append(' '.join(str(k) for k in range(1, n + 1)))
        else:
            divs = []
            d = 1
            while d * d <= g:
                if g % d == 0:
                    divs.append(d)
                    if d != g // d:
                        divs.append(g // d)
                d += 1
            divs.sort()
            out_lines.append(' '.join(map(str, divs)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

